#include <stdlib.h>
#include <limits.h>
#define MAX 100
int maxFlow(int graph[][MAX], int source, int sink, int vertices) {
    int parent[vertices];
    int max_flow = 0;
    while (bfs(graph, source, sink, parent)) {
        int path_flow = INT_MAX;
        int s = sink;
        while (s != source) {
            path_flow = (path_flow < graph[parent[s]][s]) ? path_flow : graph[parent[s]][s];
            s = parent[s];
        }
        max_flow += path_flow;
        int v = sink;
        while (v != source) {
            int u = parent[v];
            graph[u][v] -= path_flow;
            graph[v][u] += path_flow;
            v = parent[v];
        }
    }
    return max_flow;
}
int bfs(int graph[][MAX], int source, int sink, int parent[]) {
    int visited[MAX] = {0};
    int q[MAX];
    int front = 0, rear = 0;
    q[rear++] = source;
    visited[source] = 1;
    parent[source] = -1;
    while (front < rear) {
        int u = q[front++];
        for (int ind = 0; ind < MAX; ind++) {
            if (!visited[ind] && graph[u][ind] > 0) {
                q[rear++] = ind;
                parent[ind] = u;
                visited[ind] = 1;
                if (ind == sink) {
                    return 1;
                }
            }
        }
    }
    return 0;
}
