import java.util.Queue;
import java.util.LinkedList;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.IOException;
public class Main {
    static final int MAX = 100;
    public static int maxFlow(int[][] graph, int source, int sink, int vertices) {
        int[] parent = new int[vertices];
        int max_flow = 0;
        while (bfs(graph, source, sink, parent)) {
            int path_flow = Integer.MAX_VALUE;
            int s = sink;
            while (s != source) {
                path_flow = Math.min(path_flow, graph[parent[s]][s]);
                s = parent[s];
            }
            max_flow += path_flow;
            int v = sink;
            while (v != source) {
                int u = parent[v];
                graph[u][v] -= path_flow;
                graph[v][u] += path_flow;
                v = parent[v];
            }
        }
        return max_flow;
    }
    public static boolean bfs(int[][] graph, int source, int sink, int[] parent) {
        boolean[] visited = new boolean[MAX];
        Queue<Integer> q = new LinkedList<>();
        q.add(source);
        visited[source] = true;
        parent[source] = -1;
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int ind = 0; ind < MAX; ind++) {
                if (!visited[ind] && graph[u][ind] > 0) {
                    q.add(ind);
                    parent[ind] = u;
                    visited[ind] = true;
                    if (ind == sink) {
                        return true;
                    }
                }
            }
        }
        return false;
    }
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int N = Integer.parseInt(br.readLine());
        for (int i = 0; i < N; i++) {
            String[] input = br.readLine().split(" ");
            int K = Integer.parseInt(input[0]);
            int M = Integer.parseInt(input[1]);
            int[] sumana = new int[K];
            input = br.readLine().split(" ");
            for (int j = 0; j < K; j++) {
                sumana[j] = Integer.parseInt(input[j]);
            }
            int[][] friends = new int[M][K];
            for (int j = 0; j < M; j++) {
                input = br.readLine().split(" ");
                for (int k = 0; k < K; k++) {
                    friends[j][k] = Integer.parseInt(input[k]);
                }
            }
            int[][] graph = new int[MAX][MAX];
            int source = 0;
            int sink = MAX - 1;
            for (int j = 0; j < M; j++) {
                graph[source][j + 1] = 1;
            }
            for (int j = 0; j < M; j++) {
                for (int k = 0; k < K; k++) {
                    if (friends[j][k] > 1) {
                        graph[j + 1][M + k + 1] = friends[j][k] - 1;
                    }
                }
            }
            for (int j = 0; j < K; j++) {
                if (sumana[j] > 0) {
                    graph[M + j + 1][sink] = 1;
                }
            }
            System.out.println("Case " + (i + 1) + ": " + maxFlow(graph, source, sink, MAX));
        }
    }
}
